/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to a PDF file. &IsAuthorized = SecGAMIsAuthByFunctionalityKey.Udp(!'<Check_Is_Authenticated>') If &IsAuthorized
LoadWWPContext.Call(&Context)
Do 'LoadGridState'
&Title = "Lista de Lançamento Notas Fiscais"
//Report Template Source Header &AppName = "DVelop Software Solutions" &Phone = !"+1 550 8923" &Mail = !"info@mail.com" &Website = !"http://www.web.com" &AddressLine1 = !"French Boulevard 2859" &AddressLine2 = !"Downtown" &AddressLine3 = !"Paris, France" Print printTitle End Footer &PageInfo = "Page: " + &Page.ToString().Trim() &DateInfo = "Date: " + &Today.ToFormattedString() Print printFooter End
Do 'PrintFilters'
Do 'PrintColumnTitles'
Do 'PrintData'
Do 'PrintFooter'
EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'PrintFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &NfeNum.IsEmpty() print printBlockFilterNfeNum EndIf If not &NfePedCod.IsEmpty() print printBlockFilterNfePedCod EndIf If not &NfeCod.IsEmpty() print printBlockFilterNfeCod EndIf If not &NfeCliCod.IsEmpty() print printBlockFilterNfeCliCod EndIf If not &NfeCliRaz.IsEmpty() print printBlockFilterNfeCliRaz EndIf If not &EmpCod.IsEmpty() print printBlockFilterEmpCod EndIf If not &NfeProTer.IsEmpty() &FilterNfeProTerValueDescription = &NfeProTer.EnumerationDescription()
print printBlockFilterNfeProTer EndIf If not &FilCod.IsEmpty() print printBlockFilterFilCod EndIf If not &NfeSts.IsEmpty() &FilterNfeStsValueDescription = &NfeSts.EnumerationDescription()
print printBlockFilterNfeSts EndIf If not &NfeDtaFat.IsEmpty() print printBlockFilterNfeDtaFat EndIf If not &NfeDtaFat_To.IsEmpty() &NfeDtaFat_To_Description = format('%1 (%2)', "Entrada", "à") print printBlockFilterNfeDtaFat_To EndIf If not &NfeDtaEms.IsEmpty() print printBlockFilterNfeDtaEms EndIf If not &NfeDtaEms_To.IsEmpty() &NfeDtaEms_To_Description = format('%1 (%2)', "Em.", "à") print printBlockFilterNfeDtaEms_To EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod FilCod (NfeNum) when &OrderedBy = 1 order FilCod when &OrderedBy = 2 AND &OrderedDsc = False order (FilCod) when &OrderedBy = 2 AND &OrderedDsc = True order NfeCod when &OrderedBy = 3 AND &OrderedDsc = False order (NfeCod) when &OrderedBy = 3 AND &OrderedDsc = True order NfeNum when &OrderedBy = 4 AND &OrderedDsc = False order (NfeNum) when &OrderedBy = 4 AND &OrderedDsc = True order NfePedCod when &OrderedBy = 5 AND &OrderedDsc = False order (NfePedCod) when &OrderedBy = 5 AND &OrderedDsc = True order NfeDtaEms when &OrderedBy = 6 AND &OrderedDsc = False order (NfeDtaEms) when &OrderedBy = 6 AND &OrderedDsc = True order NfeDtaFat when &OrderedBy = 7 AND &OrderedDsc = False order (NfeDtaFat) when &OrderedBy = 7 AND &OrderedDsc = True order NfeCliCod when &OrderedBy = 8 AND &OrderedDsc = False order (NfeCliCod) when &OrderedBy = 8 AND &OrderedDsc = True order NfeVlrTot when &OrderedBy = 9 AND &OrderedDsc = False order (NfeVlrTot) when &OrderedBy = 9 AND &OrderedDsc = True order NfeSts when &OrderedBy = 10 AND &OrderedDsc = False order (NfeSts) when &OrderedBy = 10 AND &OrderedDsc = True order NfeEntSai when &OrderedBy = 11 AND &OrderedDsc = False order (NfeEntSai) when &OrderedBy = 11 AND &OrderedDsc = True
using DSwwNotasTerceiros(&NfeNum, &NfePedCod, &NfeCod, &NfeCliCod, &NfeCliRaz, &EmpCod , &NfeProTer, &FilCod, &NfeSts, &NfeDtaFat, &NfeDtaFat_To, &NfeDtaEms , &NfeDtaEms_To) if NfeCliRaz.Length() > 40 &gridNfeCliRaz = substr(upper(NfeCliRaz),1,37) + '...' Else &gridNfeCliRaz = NfeCliRaz EndIF &NfeStsDescription = NfeSts.EnumerationDescription() &NfeEntSaiDescription = NfeEntSai.EnumerationDescription()
&gridNfeLctNom = trim(str(NfeLctCod)) + '-'+ Substr(NfeLctNom, 1, 15)
Do 'BeforePrintLine' print printBlockLines_data Do 'AfterPrintLine' EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"wwNotasTerceirosGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"wwNotasTerceirosGridState")) Else &GridState.FromXml(&Session.Get(!"wwNotasTerceirosGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"NFENUM" &NfeNum.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"NFEPEDCOD" &NfePedCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"NFECOD" &NfeCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"NFECLICOD" &NfeCliCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"NFECLIRAZ" &NfeCliRaz.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"EMPCOD" &EmpCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"NFEPROTER" &NfeProTer.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FILCOD" &FilCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"NFESTS" &NfeSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"NFEDTAFAT" &NfeDtaFat.FromString(&GridStateFilterValue.Value) &NfeDtaFat_To.FromString(&GridStateFilterValue.ValueTo) Case &GridStateFilterValue.Name = !"NFEDTAEMS" &NfeDtaEms.FromString(&GridStateFilterValue.Value) &NfeDtaEms_To.FromString(&GridStateFilterValue.ValueTo) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
